function Projects() {
  return (
    <section id="projects" className="section">
      <h2 className="section-title">Projects</h2>
      <div className="projects-grid">
        <div className="project-card">
          <h3>CRM App</h3>
          <p>Full Stack CRM with JWT Authentication & Dashboard</p>
        </div>
        <div className="project-card">
          <h3>Chat App</h3>
          <p>Socket.io based live messaging app</p>
        </div>
      </div>
    </section>
  );
}

export default Projects;
